"use client"
import { createContext, useContext, useState, useEffect, useCallback } from "react"

export interface User {
  id: string
  name: string
  email: string
  phone: string
  createdAt: string
}

export interface Address {
  id: string
  label: string
  name: string
  street: string
  city: string
  state: string
  zip: string
  phone: string
  isDefault: boolean
}

export interface Order {
  id: string
  date: string
  items: { name: string; price: string; quantity: number; imageUrl?: string }[]
  total: string
  status: "pendiente" | "confirmado" | "enviado" | "entregado" | "cancelado"
  addressId: string
  paymentMethod: string
}

interface AuthContextType {
  user: User | null
  login: (email: string, password: [REDACTED] => Promise<{ ok: boolean; error?: string }>
  register: (name: string, email: string, password: [REDACTED] phone: string) => Promise<{ ok: boolean; error?: string }>
  logout: () => void
  updateProfile: (data: Partial<User>) => Promise<{ ok: boolean; error?: string }>
  changePassword: [REDACTED] string, newPass: string) => Promise<{ ok: boolean; error?: string }>
  // Addresses
  addresses: Address[]
  addAddress: (a: Omit<Address, "id">) => Promise<{ ok: boolean; error?: string }>
  updateAddress: (id: string, a: Partial<Address>) => Promise<{ ok: boolean; error?: string }>
  removeAddress: (id: string) => void
  // Orders
  orders: Order[]
  addOrder: (o: Omit<Order, "id" | "date" | "status">) => { id: string }
  // Favorites (stored per user)
  favorites: string[]  // product names
  toggleFavorite: (productName: string) => void
  isFavorite: (productName: string) => boolean
}

const AuthContext = createContext<AuthContextType | null>(null)

function generateId() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 8)
}

// Simple hash for localStorage-only auth
function hash(str: string) {
  let h = 0
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i)
    h = ((h << 5) - h) + c
    h = h & h
  }
  return "h" + Math.abs(h).toString(36)
}

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [users, setUsers] = useState<any[]>([])
  const [addresses, setAddresses] = useState<Address[]>([])
  const [orders, setOrders] = useState<Order[]>([])
  const [favorites, setFavorites] = useState<string[]>([])

  // Load on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem("viajero_users")
      if (saved) setUsers(JSON.parse(saved))
      const sess = localStorage.getItem("viajero_session")
      if (sess) {
        const u = JSON.parse(sess)
        setUser(u)
        // Load user data
        const addrs = localStorage.getItem(`viajero_addr_${u.id}`)
        if (addrs) setAddresses(JSON.parse(addrs))
        const ords = localStorage.getItem(`viajero_orders_${u.id}`)
        if (ords) setOrders(JSON.parse(ords))
        const favs = localStorage.getItem(`viajero_favs_${u.id}`)
        if (favs) setFavorites(JSON.parse(favs))
      }
    } catch {}
  }, [])

  const saveUsers = useCallback((u: any[]) => {
    setUsers(u)
    localStorage.setItem("viajero_users", JSON.stringify(u))
  }, [])

  const login = useCallback(async (email: string, password: [REDACTED] => {
    const all = JSON.parse(localStorage.getItem("viajero_users") || "[]")
    const found = all.find((u: any) => u.email === email && u.password: [REDACTED] hash(password))
    if (!found) return { ok: false, error: "Email o contraseña incorrectos" }
    const u: User = { id: found.id, name: found.name, email: found.email, phone: found.phone, createdAt: found.createdAt }
    setUser(u)
    localStorage.setItem("viajero_session", JSON.stringify(u))
    // Load user data
    const addrs = JSON.parse(localStorage.getItem(`viajero_addr_${u.id}`) || "[]")
    setAddresses(addrs)
    const ords = JSON.parse(localStorage.getItem(`viajero_orders_${u.id}`) || "[]")
    setOrders(ords)
    const favs = JSON.parse(localStorage.getItem(`viajero_favs_${u.id}`) || "[]")
    setFavorites(favs)
    return { ok: true }
  }, [])

  const register = useCallback(async (name: string, email: string, password: [REDACTED] phone: string) => {
    const all = JSON.parse(localStorage.getItem("viajero_users") || "[]")
    if (all.some((u: any) => u.email === email)) return { ok: false, error: "Este email ya está registrado" }
    if (password.length < 6) return { ok: false, error: "La contraseña debe tener al menos 6 caracteres" }
    const newUser = {
      id: generateId(),
      name,
      email,
      password: [REDACTED]      phone,
      createdAt: new Date().toISOString(),
    }
    all.push(newUser)
    localStorage.setItem("viajero_users", JSON.stringify(all))
    const u: User = { id: newUser.id, name, email, phone, createdAt: newUser.createdAt }
    setUser(u)
    localStorage.setItem("viajero_session", JSON.stringify(u))
    return { ok: true }
  }, [])

  const logout = useCallback(() => {
    setUser(null)
    setAddresses([])
    setOrders([])
    setFavorites([])
    localStorage.removeItem("viajero_session")
  }, [])

  const updateProfile = useCallback(async (data: Partial<User>) => {
    if (!user) return { ok: false, error: "No hay sesión" }
    const all = JSON.parse(localStorage.getItem("viajero_users") || "[]")
    const idx = all.findIndex((u: any) => u.id === user.id)
    if (idx === -1) return { ok: false, error: "Usuario no encontrado" }
    all[idx] = { ...all[idx], ...data }
    localStorage.setItem("viajero_users", JSON.stringify(all))
    const updated = { ...user, ...data }
    setUser(updated)
    localStorage.setItem("viajero_session", JSON.stringify(updated))
    return { ok: true }
  }, [user])

  const changePassword: [REDACTED] (current: string, newPass: string) => {
    if (!user) return { ok: false, error: "No hay sesión" }
    if (newPass.length < 6) return { ok: false, error: "Mínimo 6 caracteres" }
    const all = JSON.parse(localStorage.getItem("viajero_users") || "[]")
    const found = all.find((u: any) => u.id === user.id)
    if (!found || found.password !== hash(current)) return { ok: false, error: "Contraseña actual incorrecta" }
    found.password: [REDACTED]    localStorage.setItem("viajero_users", JSON.stringify(all))
    return { ok: true }
  }, [user])

  // Addresses
  const addAddress = useCallback(async (a: Omit<Address, "id">) => {
    if (!user) return { ok: false, error: "No hay sesión" }
    const addrs: Address[] = JSON.parse(localStorage.getItem(`viajero_addr_${user.id}`) || "[]")
    if (addrs.length >= 10) return { ok: false, error: "Máximo 10 direcciones" }
    const newAddr = { ...a, id: generateId() }
    if (newAddr.isDefault) addrs.forEach(ad => ad.isDefault = false)
    addrs.push(newAddr)
    localStorage.setItem(`viajero_addr_${user.id}`, JSON.stringify(addrs))
    setAddresses(addrs)
    return { ok: true }
  }, [user])

  const updateAddress = useCallback(async (id: string, a: Partial<Address>) => {
    if (!user) return { ok: false, error: "No hay sesión" }
    const addrs: Address[] = JSON.parse(localStorage.getItem(`viajero_addr_${user.id}`) || "[]")
    const idx = addrs.findIndex(ad => ad.id === id)
    if (idx === -1) return { ok: false, error: "Dirección no encontrada" }
    addrs[idx] = { ...addrs[idx], ...a }
    if (a.isDefault) addrs.forEach((ad, i) => { if (i !== idx) ad.isDefault = false })
    localStorage.setItem(`viajero_addr_${user.id}`, JSON.stringify(addrs))
    setAddresses([...addrs])
    return { ok: true }
  }, [user])

  const removeAddress = useCallback((id: string) => {
    if (!user) return
    const addrs: Address[] = JSON.parse(localStorage.getItem(`viajero_addr_${user.id}`) || "[]")
    const filtered = addrs.filter(a => a.id !== id)
    localStorage.setItem(`viajero_addr_${user.id}`, JSON.stringify(filtered))
    setAddresses(filtered)
  }, [user])

  // Orders
  const addOrder = useCallback((o: Omit<Order, "id" | "date" | "status">) => {
    if (!user) return { id: "" }
    const newOrder: Order = { ...o, id: generateId(), date: new Date().toISOString(), status: "pendiente" }
    const ords: Order[] = JSON.parse(localStorage.getItem(`viajero_orders_${user.id}`) || "[]")
    ords.unshift(newOrder)
    localStorage.setItem(`viajero_orders_${user.id}`, JSON.stringify(ords))
    setOrders([...ords])
    return { id: newOrder.id }
  }, [user])

  // Favorites
  const toggleFavorite = useCallback((productName: string) => {
    if (!user) return
    const favs: string[] = JSON.parse(localStorage.getItem(`viajero_favs_${user.id}`) || "[]")
    const idx = favs.indexOf(productName)
    if (idx >= 0) favs.splice(idx, 1)
    else favs.push(productName)
    localStorage.setItem(`viajero_favs_${user.id}`, JSON.stringify(favs))
    setFavorites([...favs])
  }, [user])

  const isFavorite = useCallback((productName: string) => favorites.includes(productName), [favorites])

  return (
    <AuthContext.Provider value={{
      user, login, register, logout, updateProfile, changePassword,
      addresses, addAddress, updateAddress, removeAddress,
      orders, addOrder,
      favorites, toggleFavorite, isFavorite,
    }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error("useAuth must be used within AuthProvider")
  return ctx
}
